    name = (cfg_.optimizer_name or "adamw").lower()
    if name == "adamw":
        return torch.optim.AdamW(
            model_.parameters(), lr=cfg_.lr, weight_decay=cfg_.weight_decay,
            betas=(0.9, 0.95),
